closerProps.description:
Параметры кнопки закрытия
@property {boolean} [hasCloser] - Управляет отображением кнопки закрытия уведомления
@property {string} [closerWrapperClassName] - Дополнительный класс враппера кнопки "закрыть"
@property {string} [closerClassName] - Дополнительный класс кнопки "закрыть"
@property {boolean} [divider] - Показывать разделитель
@property {import('@alfalab/core-components-icon-button').IconButtonProps['view']} [view] - Вид кнопки закрытия

demos.desktop:
render(() => {
    const [anchorToastOpen, setAnchorToastOpen] = React.useState(false);

    const [fixedToastOpen, setFixedToastOpen] = React.useState(false);

    const [buttonElement, setButtonElement] = React.useState(null);

    const handleButtonRef = (node) => {
        setButtonElement(node);
    };

    return (
        <Space direction='horizontal' size={24}>
            <Toast
                breakpoint={BREAKPOINT}
                open={anchorToastOpen}
                anchorElement={buttonElement}
                position='right'
                offset={[0, 24]}
                title='Пример уведомления'
                hasCloser={false}
                block={false}
                onClose={() => {
                    setAnchorToastOpen(false);
                }}
                autoCloseDelay={1500}
            />
            <Toast
                breakpoint={BREAKPOINT}
                open={fixedToastOpen}
                badge='positive-checkmark'
                title='Пример уведомления с кнопкой и крестиком'
                hasCloser={true}
                bottomButtonPosition={isMobile()}
                onClose={() => {
                    setFixedToastOpen(false);
                }}
                autoCloseDelay={3000}
                actionButton={
                    <Button
                        breakpoint={BREAKPOINT}
                        size={isMobile() ? 40 : 48}
                        view='text'
                        colors='inverted'
                        onClick={() => {
                            setFixedToastOpen(false);
                        }}
                    >
                        Отменить
                    </Button>
                }
                style={{ left: !isMobile() && '20%' }}
            />
            <Button
                breakpoint={BREAKPOINT}
                onClick={() => {
                    setFixedToastOpen(true);
                }}
            >
                Показать снизу
            </Button>
            {!isMobile() && (
                <Button
                    breakpoint={BREAKPOINT}
                    ref={handleButtonRef}
                    onClick={() => {
                        setAnchorToastOpen(true);
                    }}
                >
                    Показать рядом
                </Button>
            )}
        </Space>
    );
});
